parameters.jsCode:
const body = $input.item.json.body || $input.item.json;

// Vapi sends call data in the message object
const message = body.message || body;
const call    = message.call || message;

const customerPhone = call.customer?.number || '';
const customerName  = call.customer?.name  || 'there';
const firstName     = customerName.split(' ')[0] || customerName;

// Only send SMS if customer answered (not no-answer/voicemail)
const endedReason = call.endedReason || message.endedReason || '';
const answered = !['no-answer','busy','failed','voicemail'].includes(endedReason);

if (!customerPhone || !answered) {
  return [];
}

return [{ json: { customerPhone, firstName, endedReason } }];

